package server

import (
	"database/sql"
	"log"
	"net/http"
	"os"
	"strings"

	"forum.com/m/src/database"
)

var dbConn *sql.DB

func StartServer() {
	var err error
	dbConn, err = database.Connect()
	if err != nil {
		log.Fatalf("DB error: %v", err)
	}

	if err := database.Migrate(dbConn); err != nil {
		log.Fatalf("Migration error: %v", err)
	}

	port := os.Getenv("PORT")
	if port == "" {
		port = "8080"
	}
	if !strings.HasPrefix(port, ":") {
		port = ":" + port
	}

	mux := http.NewServeMux()

	mux.HandleFunc("/", helloHandler)
	mux.HandleFunc("/chat", chatHandler)
	mux.HandleFunc("/api/messages", messagesAPIHandler)
	mux.HandleFunc("/register", registerHandler)
	mux.HandleFunc("/login", loginHandler)
	mux.HandleFunc("/logout", logoutHandler)

	mux.Handle("/static/",
		http.StripPrefix("/static/", http.FileServer(http.Dir("static"))),
	)

	log.Printf("Server running on %s", port)
	log.Fatal(http.ListenAndServe(port, mux))
}

package server

import (
	"encoding/json"
	"net/http"
	"strings"
)

type APIResponse struct {
	Success bool        `json:"success"`
	Message string      `json:"message,omitempty"`
	Data    interface{} `json:"data,omitempty"`
}

type MessageBody struct {
	Category string `json:"category"`
	Content  string `json:"content"`
}

func messagesAPIHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	switch r.Method {
	case http.MethodGet:
		handleGetMessages(w, r)
	case http.MethodPost:
		handlePostMessage(w, r)
	default:
		json.NewEncoder(w).Encode(APIResponse{
			Success: false,
			Message: "method not allowed",
		})
	}
}

func handleGetMessages(w http.ResponseWriter, r *http.Request) {
	categoryName := strings.TrimSpace(r.URL.Query().Get("category"))

	if categoryName == "" {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "category manquant",
		})
		return
	}

	cat, err := GetCategoryByName(categoryName, dbConn)
	if err != nil {
		writeJSON(w, http.StatusNotFound, APIResponse{
			Success: false,
			Message: "catégorie introuvable",
		})
		return
	}

	messages, err := GetMessages(cat.ID, dbConn)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{
			Success: false,
			Message: "erreur messages",
		})
		return
	}

	writeJSON(w, http.StatusOK, APIResponse{
		Success: true,
		Data:    messages,
	})
}

func handlePostMessage(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		writeJSON(w, http.StatusUnauthorized, APIResponse{
			Success: false,
			Message: "Non authentifié",
		})
		return
	}

	var body MessageBody

	err = json.NewDecoder(r.Body).Decode(&body)
	if err != nil {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "json invalide",
		})
		return
	}

	categoryName := strings.TrimSpace(body.Category)
	content := strings.TrimSpace(body.Content)

	if categoryName == "" || content == "" {
		writeJSON(w, http.StatusBadRequest, APIResponse{
			Success: false,
			Message: "paramètres manquants",
		})
		return
	}

	cat, err := GetCategoryByName(categoryName, dbConn)
	if err != nil {
		writeJSON(w, http.StatusNotFound, APIResponse{
			Success: false,
			Message: "catégorie introuvable",
		})
		return
	}

	msg, err := PostMessage(cat.ID, user.ID, content, dbConn)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{
			Success: false,
			Message: "erreur message",
		})
		return
	}

	writeJSON(w, http.StatusCreated, APIResponse{
		Success: true,
		Data:    msg,
	})
}

func writeJSON(w http.ResponseWriter, status int, data APIResponse) {
	w.Header().Set("Content-Type", "application/json; charset=utf-8")
	w.WriteHeader(status)
	_ = json.NewEncoder(w).Encode(data)
}

package server

import (
	"html"
	"net/http"
	"strings"
)

func registerHandler(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodGet:
		renderRegisterForm(w, "")
	case http.MethodPost:
		username := strings.TrimSpace(r.FormValue("username"))
		password := r.FormValue("password")

		if username == "" || password == "" {
			renderRegisterForm(w, "Veuillez remplir tous les champs.")
			return
		}

		userID, err := createUser(username, password)
		if err != nil {
			if strings.Contains(strings.ToLower(err.Error()), "duplicate") {
				renderRegisterForm(w, "Ce nom d'utilisateur existe déjà.")
				return
			}
			http.Error(w, "Erreur serveur : "+html.EscapeString(err.Error()), http.StatusInternalServerError)
			return
		}

		sessionID, err := CreateSession(userID, dbConn)
		if err != nil {
			http.Error(w, "Erreur serveur", http.StatusInternalServerError)
			return
		}

		http.SetCookie(w, &http.Cookie{
			Name:     "session_id",
			Value:    sessionID,
			Path:     "/",
			MaxAge:   86400,
			HttpOnly: true,
			SameSite: http.SameSiteLaxMode,
		})

		http.Redirect(w, r, "/", http.StatusSeeOther)
	}
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodGet:
		renderLoginForm(w, "")
	case http.MethodPost:
		username := strings.TrimSpace(r.FormValue("username"))
		password := r.FormValue("password")

		if username == "" || password == "" {
			renderLoginForm(w, "Veuillez remplir tous les champs.")
			return
		}

		userID, ok, err := authenticateUser(username, password)
		if err != nil {
			http.Error(w, "Erreur serveur : "+html.EscapeString(err.Error()), http.StatusInternalServerError)
			return
		}
		if !ok {
			renderLoginForm(w, "Identifiants incorrects.")
			return
		}

		sessionID, err := CreateSession(userID, dbConn)
		if err != nil {
			http.Error(w, "Erreur serveur", http.StatusInternalServerError)
			return
		}

		http.SetCookie(w, &http.Cookie{
			Name:     "session_id",
			Value:    sessionID,
			Path:     "/",
			MaxAge:   86400,
			HttpOnly: true,
			SameSite: http.SameSiteLaxMode,
		})

		http.Redirect(w, r, "/", http.StatusSeeOther)
	}
}

func logoutHandler(w http.ResponseWriter, r *http.Request) {
	cookie, err := r.Cookie("session_id")
	if err == nil {
		DestroySession(cookie.Value, dbConn)
	}

	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    "",
		Path:     "/",
		MaxAge:   -1,
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
	})

	http.Redirect(w, r, "/", http.StatusSeeOther)
}

func renderRegisterForm(w http.ResponseWriter, message string) {
	data := struct {
		Message string
	}{
		Message: message,
	}
	_ = authTemplates.ExecuteTemplate(w, "register.html", data)
}

func renderLoginForm(w http.ResponseWriter, message string) {
	data := struct {
		Message string
	}{
		Message: message,
	}
	_ = authTemplates.ExecuteTemplate(w, "login.html", data)
}

package server

import (
	"database/sql"

	"golang.org/x/crypto/bcrypt"
)

func createUser(username, password string) (int, error) {
	hash, err := bcrypt.GenerateFromPassword([]byte(password), bcrypt.DefaultCost)
	if err != nil {
		return 0, err
	}

	var id int

	err = dbConn.QueryRow(`
		INSERT INTO users (username, password_hash)
		VALUES ($1, $2)
		RETURNING id
	`, username, string(hash)).Scan(&id)

	return id, err
}

func authenticateUser(username, password string) (int, bool, error) {
	var userID int
	var hash string

	err := dbConn.QueryRow(`
		SELECT id, password_hash
		FROM users
		WHERE username = $1
	`, username).Scan(&userID, &hash)

	if err != nil {
		if err == sql.ErrNoRows {
			return 0, false, nil
		}
		return 0, false, err
	}

	if err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(password)); err != nil {
		return 0, false, nil
	}

	return userID, true, nil
}

package server

import (
	"database/sql"
	"time"
)

type Message struct {
	ID         int       `json:"id"`
	CategoryID int       `json:"category_id"`
	UserID     int       `json:"user_id"`
	Username   string    `json:"username"`
	Content    string    `json:"content"`
	CreatedAt  time.Time `json:"created_at"`
}

type Category struct {
	ID          int    `json:"id"`
	Name        string `json:"name"`
	Description string `json:"description"`
}

func GetCategories(dbConn *sql.DB) ([]Category, error) {
	rows, err := dbConn.Query(`
		SELECT id, name, description
		FROM categories
		ORDER BY name
	`)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var categories []Category

	for rows.Next() {
		var c Category
		if err := rows.Scan(&c.ID, &c.Name, &c.Description); err != nil {
			return nil, err
		}
		categories = append(categories, c)
	}

	return categories, rows.Err()
}

func GetCategoryByName(name string, dbConn *sql.DB) (*Category, error) {
	var c Category

	err := dbConn.QueryRow(`
		SELECT id, name, description
		FROM categories
		WHERE LOWER(TRIM(name)) = LOWER(TRIM($1))
		LIMIT 1
	`, name).Scan(&c.ID, &c.Name, &c.Description)

	if err == nil {
		return &c, nil
	}

	if err != sql.ErrNoRows {
		return nil, err
	}

	err = dbConn.QueryRow(`
		INSERT INTO categories (name, description)
		VALUES ($1, $2)
		ON CONFLICT (name) DO UPDATE SET name = EXCLUDED.name
		RETURNING id, name, description
	`, name, "Catégorie "+name).Scan(&c.ID, &c.Name, &c.Description)

	if err != nil {
		return nil, err
	}

	return &c, nil
}

package server

import (
	"crypto/rand"
	"database/sql"
	"encoding/hex"
	"errors"
	"net/http"
	"time"
)

type User struct {
	ID       int
	Username string
}

func GetSessionUser(r *http.Request, dbConn *sql.DB) (*User, error) {
	cookie, err := r.Cookie("session_id")
	if err != nil {
		return nil, errors.New("no session")
	}

	sessionID := cookie.Value

	var userID int
	var expiresAt time.Time

	err = dbConn.QueryRow(`
		SELECT user_id, expires_at
		FROM sessions
		WHERE id = $1
	`, sessionID).Scan(&userID, &expiresAt)

	if err != nil {
		return nil, errors.New("invalid session")
	}

	if time.Now().After(expiresAt) {
		_, _ = dbConn.Exec(`DELETE FROM sessions WHERE id = $1`, sessionID)
		return nil, errors.New("session expired")
	}

	var username string
	err = dbConn.QueryRow(`
		SELECT username
		FROM users
		WHERE id = $1
	`, userID).Scan(&username)

	if err != nil {
		return nil, err
	}

	return &User{ID: userID, Username: username}, nil
}

func CreateSession(userID int, dbConn *sql.DB) (string, error) {
	sessionIDBytes := make([]byte, 32)
	_, err := rand.Read(sessionIDBytes)
	if err != nil {
		return "", err
	}

	sessionID := hex.EncodeToString(sessionIDBytes)
	expiresAt := time.Now().Add(24 * time.Hour)

	_, err = dbConn.Exec(`
		INSERT INTO sessions (id, user_id, expires_at)
		VALUES ($1, $2, $3)
	`, sessionID, userID, expiresAt)

	return sessionID, err
}

func DestroySession(sessionID string, dbConn *sql.DB) error {
	_, err := dbConn.Exec(`DELETE FROM sessions WHERE id = $1`, sessionID)
	return err
}

package database

import (
	"database/sql"
	"log"
	"os"

	_ "github.com/lib/pq"
)

func Connect() (*sql.DB, error) {
	dsn := os.Getenv("DATABASE_URL")

	if dsn == "" {
		log.Fatal("DATABASE_URL manquant")
	}

	log.Println("Connecting DB...")

	db, err := sql.Open("postgres", dsn)
	if err != nil {
		return nil, err
	}

	if err := db.Ping(); err != nil {
		return nil, err
	}

	log.Println("DB connected")

	return db, nil
}

