type ProfilePageData struct {
	User           *User
	JoinedAt       string
	MessageCount   int
	RecentMessages []RecentMessage
	Success        string
	Error          string
}

type RecentMessage struct {
	Content      string
	CategoryName string
	CreatedAt    time.Time
}

func profileHandler(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		http.Redirect(w, r, "/login", http.StatusSeeOther)
		return
	}

	if r.Method == http.MethodPost {
		updateProfile(w, r, user)
		return
	}

	data := buildProfileData(user, "", "")
	_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
}

func buildProfileData(user *User, success, errMsg string) ProfilePageData {
	var messageCount int
	_ = dbConn.QueryRow(`SELECT COUNT(*) FROM messages WHERE user_id = $1`, user.ID).Scan(&messageCount)

	var joinedAt time.Time
	_ = dbConn.QueryRow(`SELECT created_at FROM users WHERE id = $1`, user.ID).Scan(&joinedAt)

	rows, err := dbConn.Query(`
		SELECT m.content, c.name, m.created_at
		FROM messages m
		JOIN categories c ON c.id = m.category_id
		WHERE m.user_id = $1
		ORDER BY m.created_at DESC
		LIMIT 5
	`, user.ID)
	if err != nil {
		rows = nil
	}

	var recent []RecentMessage
	if rows != nil {
		defer rows.Close()
		for rows.Next() {
			var m RecentMessage
			if rows.Scan(&m.Content, &m.CategoryName, &m.CreatedAt) == nil {
				recent = append(recent, m)
			}
		}
	}

	return ProfilePageData{
		User:           user,
		JoinedAt:       joinedAt.Format("2 January 2006"),
		MessageCount:   messageCount,
		RecentMessages: recent,
		Success:        success,
		Error:          errMsg,
	}
}

func updateProfile(w http.ResponseWriter, r *http.Request, user *User) {
	username := strings.TrimSpace(r.FormValue("username"))
	bio := strings.TrimSpace(r.FormValue("bio"))

	if username == "" {
		data := buildProfileData(user, "", "Le nom d'utilisateur ne peut pas être vide.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	if username != user.Username {
		var exists int
		_ = dbConn.QueryRow(`SELECT COUNT(*) FROM users WHERE username = $1 AND id != $2`, username, user.ID).Scan(&exists)
		if exists > 0 {
			data := buildProfileData(user, "", "Ce nom d'utilisateur est déjà pris.")
			_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
			return
		}
	}

	_, err := dbConn.Exec(`UPDATE users SET username = $1, bio = $2 WHERE id = $3`, username, bio, user.ID)
	if err != nil {
		data := buildProfileData(user, "", "Erreur lors de la mise à jour.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	user.Username = username
	user.Bio = bio

	data := buildProfileData(user, "Profil mis à jour.", "")
	_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
}

func profileAvatarHandler(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		writeJSON(w, http.StatusUnauthorized, APIResponse{Success: false, Message: "Non authentifié"})
		return
	}

	if err := r.ParseMultipartForm(2 << 20); err != nil {
		writeJSON(w, http.StatusBadRequest, APIResponse{Success: false, Message: "Fichier trop volumineux (max 2Mo)"})
		return
	}

	file, header, err := r.FormFile("avatar")
	if err != nil {
		writeJSON(w, http.StatusBadRequest, APIResponse{Success: false, Message: "Fichier manquant"})
		return
	}
	defer file.Close()

	contentType := header.Header.Get("Content-Type")
	if !strings.HasPrefix(contentType, "image/") {
		writeJSON(w, http.StatusBadRequest, APIResponse{Success: false, Message: "Le fichier doit être une image"})
		return
	}

	ext := filepath.Ext(header.Filename)
	if ext == "" {
		switch contentType {
		case "image/jpeg":
			ext = ".jpg"
		case "image/png":
			ext = ".png"
		case "image/gif":
			ext = ".gif"
		case "image/webp":
			ext = ".webp"
		default:
			ext = ".jpg"
		}
	}

	allowedExts := map[string]bool{".jpg": true, ".jpeg": true, ".png": true, ".gif": true, ".webp": true}
	if !allowedExts[strings.ToLower(ext)] {
		writeJSON(w, http.StatusBadRequest, APIResponse{Success: false, Message: "Format non supporté (jpg, png, gif, webp)"})
		return
	}

	if user.AvatarURL != "" {
		oldPath := "." + user.AvatarURL
		os.Remove(oldPath)
	}

	os.MkdirAll("static/avatars", 0755)

	filename := fmt.Sprintf("%d%s", user.ID, ext)
	savePath := filepath.Join("static", "avatars", filename)

	dst, err := os.Create(savePath)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{Success: false, Message: "Erreur serveur"})
		return
	}
	defer dst.Close()

	if _, err := io.Copy(dst, file); err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{Success: false, Message: "Erreur serveur"})
		return
	}

	avatarURL := "/static/avatars/" + filename
	_, err = dbConn.Exec(`UPDATE users SET avatar_url = $1 WHERE id = $2`, avatarURL, user.ID)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, APIResponse{Success: false, Message: "Erreur serveur"})
		return
	}

	writeJSON(w, http.StatusOK, APIResponse{Success: true, Data: map[string]string{"avatar_url": avatarURL}})
}

func profilePasswordHandler(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		http.Redirect(w, r, "/login", http.StatusSeeOther)
		return
	}

	currentPassword := r.FormValue("current_password")
	newPassword := r.FormValue("new_password")

	if currentPassword == "" || newPassword == "" {
		data := buildProfileData(user, "", "Remplis tous les champs.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	var hash string
	_ = dbConn.QueryRow(`SELECT password_hash FROM users WHERE id = $1`, user.ID).Scan(&hash)

	if err := bcrypt.CompareHashAndPassword([]byte(hash), []byte(currentPassword)); err != nil {
		data := buildProfileData(user, "", "Mot de passe actuel incorrect.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	newHash, err := bcrypt.GenerateFromPassword([]byte(newPassword), bcrypt.DefaultCost)
	if err != nil {
		data := buildProfileData(user, "", "Erreur serveur.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	_, err = dbConn.Exec(`UPDATE users SET password_hash = $1 WHERE id = $2`, string(newHash), user.ID)
	if err != nil {
		data := buildProfileData(user, "", "Erreur serveur.")
		_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
		return
	}

	data := buildProfileData(user, "Mot de passe changé.", "")
	_ = authTemplates.ExecuteTemplate(w, "profile.html", data)
}

func profileDeleteHandler(w http.ResponseWriter, r *http.Request) {
	user, err := GetSessionUser(r, dbConn)
	if err != nil {
		writeJSON(w, http.StatusUnauthorized, APIResponse{Success: false, Message: "Non authentifié"})
		return
	}

	if user.AvatarURL != "" {
		os.Remove("." + user.AvatarURL)
	}

	_, err = dbConn.Exec(`DELETE FROM users WHERE id = $1`, user.ID)
	if err != nil {
		log.Printf("Delete account error: %v", err)
		writeJSON(w, http.StatusInternalServerError, APIResponse{Success: false, Message: "Erreur serveur"})
		return
	}

	cookie, _ := r.Cookie("session_id")
	if cookie != nil {
		DestroySession(cookie.Value, dbConn)
	}

	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    "",
		Path:     "/",
		MaxAge:   -1,
		HttpOnly: true,
		SameSite: http.SameSiteLaxMode,
	})

	writeJSON(w, http.StatusOK, APIResponse{Success: true})
}

func templateFuncs() template.FuncMap {
	return template.FuncMap{
		"uppercase": strings.ToUpper,
	}
}
