func Connect() (*sql.DB, error) {
	dsn := os.Getenv("DATABASE_URL")

	if dsn == "" {
		log.Fatal("DATABASE_URL manquant")
	}

	log.Println("Connecting DB...")

	db, err := sql.Open("postgres", dsn)
	if err != nil {
		return nil, err
	}

	if err := db.Ping(); err != nil {
		return nil, err
	}

	log.Println("DB connected")

	return db, nil
}

package config

import "os"

type Config struct {
	Port   string
	DBUser string
	DBPass string
	DBHost string
	DBName string
}

func Load() Config {
	cfg := Config{
		Port:   getEnv("APP_PORT", ":8080"),
		DBUser: getEnv("DB_USER", ""),
		DBPass: getEnv("DB_PASS", ""),
		DBHost: getEnv("DB_HOST", ""),
		DBName: getEnv("DB_NAME", ""),
	}

	if cfg.DBHost == "" || cfg.DBUser == "" || cfg.DBName == "" {
		panic("DB configuration missing (check environment variables)")
	}

	return cfg
}

func getEnv(key, fallback string) string {
	value := os.Getenv(key)
	if value == "" {
		return fallback
	}
	return value
}

@import url('base.css');
@import url('layout.css');
@import url('chat.css');
@import url('auth.css');
@import url('profile.css');

.auth-card {
    width: min(520px, 100%);
    padding: 34px;
    position: relative;
    overflow: hidden;
}

.auth-hero {
    margin-bottom: 24px;
}

.auth-hero p {
    margin: 8px 0 0;
    color: #d2d2d2;
    line-height: 1.75;
}

.auth-form {
    display: grid;
    gap: 16px;
}

.auth-form button {
    border: none;
    width: 100%;
    padding: 15px 16px;
    border-radius: 14px;
    background: var(--button-bg);
    color: var(--button-color);
    font-weight: 700;
    font-size: 1rem;
    cursor: pointer;
    transition: filter 0.2s ease, transform 0.2s ease;
}

.auth-form button:hover,
.top-nav button:hover {
    filter: brightness(1.03);
    transform: translateY(-1px);
}

.footer-link {
    margin-top: 26px;
    font-size: 0.95rem;
    text-align: center;
    color: var(--muted);
}

.footer-link a {
    color: var(--button-bg);
    text-decoration: none;
}

* {
    box-sizing: border-box;
}

:root {
    --bg: #efe6da;
    --surface: #f9f3ea;
    --surface-strong: #fff7ee;
    --panel-bg: #fbf0e6;
    --text: #30271c;
    --muted: #5e4736;
    --border: rgba(80, 65, 50, 0.12);
    --shadow: 0 20px 40px rgba(50, 40, 30, 0.12);
    --link: #4a3b2d;
    --link-hover: #7a5231;
    --button-bg: #8a5d36;
    --button-color: #f6efe4;
    --button-ghost-bg: #f2e7db;
    --button-ghost-border: rgba(120, 90, 60, 0.16);
    --button-ghost-color: #5e4330;
    --footer: #9d9d9d;
    --input-bg: #fff6ef;
    --input-border: rgba(120, 90, 60, 0.16);
    --message-bg: #f3e6d8;
    --message-border: rgba(120, 90, 60, 0.12);
    --alert-bg: #f2e4d7;
    --alert-border: rgba(120, 80, 50, 0.16);
    --alert-color: #5d4432;
    --placeholder-color: #644b37;
    --chat-border: rgba(120, 90, 60, 0.14);
    --card-hover-shadow: 0 18px 36px rgba(100, 70, 40, 0.12);
}

body.theme-dark {
    --bg: #181514;
    --surface: #241f1b;
    --surface-strong: #2f2722;
    --panel-bg: #2a221c;
    --text: #e7dfd5;
    --muted: #c6b89e;
    --border: rgba(255, 255, 255, 0.08);
    --shadow: 0 20px 40px rgba(0, 0, 0, 0.45);
    --link: #e1c4a4;
    --link-hover: #ffd591;
    --button-bg: #7f5d3b;
    --button-color: #f7ede4;
    --button-ghost-bg: #2a241f;
    --button-ghost-border: rgba(255, 255, 255, 0.12);
    --button-ghost-color: #d0b89e;
    --footer: #b8a78e;
    --input-bg: #2b231e;
    --input-border: rgba(255, 255, 255, 0.12);
    --message-bg: rgba(255, 255, 255, 0.06);
    --message-border: rgba(255, 255, 255, 0.08);
    --alert-bg: #3b322c;
    --alert-border: rgba(255, 255, 255, 0.12);
    --alert-color: #e7d5c5;
    --placeholder-color: #c6b89e;
    --chat-border: rgba(255, 255, 255, 0.09);
    --card-hover-shadow: 0 18px 36px rgba(0, 0, 0, 0.3);
}

html, body {
    min-height: 100%;
}

body {
    margin: 0;
    font-family: Georgia, "Times New Roman", serif;
    background-color: var(--bg);
    color: var(--text);
}

body::before {
    content: "";
    position: fixed;
    inset: 0;
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.6), transparent 18%);
    pointer-events: none;
}

h1 {
    margin: 0 0 18px;
    color: #ffd472;
    text-shadow: 0 1px 18px rgba(255, 163, 96, 0.24);
}

h2 {
    color: var(--muted);
    font-size: 1.15rem;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    margin: 0 0 20px;
}

h3 {
    color: var(--text);
    font-size: 1.05rem;
    margin: 0 0 6px;
}

.btn {
    padding: 14px 20px;
    border-radius: 14px;
    text-decoration: none;
    display: inline-block;
    transition: background-color 0.2s ease, color 0.2s ease, transform 0.18s ease;
    font-weight: 700;
    font-size: 0.95rem;
}

.btn:hover {
    transform: translateY(-1px);
}

.btn.primary {
    background: var(--button-bg);
    color: var(--button-color);
    box-shadow: 0 10px 26px rgba(80, 60, 40, 0.18);
}

.btn.ghost {
    background: var(--button-ghost-bg);
    border: 1px solid var(--button-ghost-border);
    color: var(--button-ghost-color);
}

label {
    display: block;
    font-size: 0.96rem;
    color: #5e4735;
}

input {
    width: 100%;
    padding: 14px 16px;
    border: 1px solid var(--input-border);
    border-radius: 14px;
    background: var(--input-bg);
    color: var(--text);
}

input:focus {
    outline: none;
    border-color: var(--button-bg);
    box-shadow: 0 0 0 4px rgba(125, 83, 52, 0.12);
}

.alert {
    padding: 14px 16px;
    border-radius: 14px;
    background: var(--alert-bg);
    border: 1px solid var(--alert-border);
    color: var(--alert-color);
}

.page-container {
    min-height: calc(100vh - 96px);
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 28px 18px 40px;
}

.card {
    width: min(520px, 100%);
    padding: 32px;
    border-radius: 18px;
    background: var(--surface);
    box-shadow: var(--shadow);
    border: 1px solid var(--border);
}

.site-header {
    position: sticky;
    top: 0;
    z-index: 10;
    background: var(--surface-strong);
    border-bottom: 1px solid var(--border);
}

.header-inner {
    max-width: 1100px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 18px 24px;
}

.logo {
    font-weight: 700;
    font-size: 1.2rem;
    color: var(--link);
    display: flex;
    align-items: center;
    gap: 14px;
}

.logo-image {
    width: 72px;
    height: 72px;
    flex-shrink: 0;
    border-radius: 18px;
    overflow: hidden;
    border: 1px solid var(--border);
    box-shadow: 0 10px 20px rgba(0, 0, 0, 0.12);
    background: var(--surface);
    object-fit: cover;
    object-position: center center;
}

.logo-text {
    color: var(--link);
    font-size: 1.2rem;
    letter-spacing: 0.04em;
    text-transform: uppercase;
}

.top-nav {
    display: flex;
    flex-wrap: nowrap;
    justify-content: flex-end;
    align-items: center;
    gap: 12px;
}

.top-nav a {
    color: var(--link);
    text-decoration: none;
    font-weight: 600;
}

.top-nav a:hover {
    color: var(--link-hover);
}

.top-nav button {
    width: auto;
    margin: 0 0 0 10px;
    padding: 10px 16px;
    border: 1px solid var(--button-ghost-border);
    background: var(--button-ghost-bg);
    color: var(--button-ghost-color);
    border-radius: 14px;
    cursor: pointer;
}

.top-nav button#theme-toggle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-weight: 700;
    letter-spacing: 0.02em;
}

.top-nav button#theme-toggle:hover {
    background: var(--button-bg);
    color: var(--button-color);
    border-color: var(--button-bg);
}

.nav-user {
    display: flex;
    align-items: center;
    gap: 8px;
}

.nav-avatar {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid var(--border);
}

.nav-avatar-initial {
    width: 28px;
    height: 28px;
    border-radius: 50%;
    background: var(--button-bg);
    color: var(--button-color);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-size: 0.78rem;
    font-weight: 700;
}

.home-root {
    max-width: 1100px;
    margin: 36px auto;
    padding: 0 18px 24px;
    padding-right: 760px;
}

.container.card {
    padding: 28px;
    margin-top: 24px;
}

.hero {
    display: block;
    padding: 44px 38px;
    background: var(--surface);
    border-radius: 20px;
    border: 1px solid var(--border);
    box-shadow: var(--shadow);
}

.hero h1 {
    font-size: clamp(2rem, 5vw, 2.8rem);
    letter-spacing: 0.02em;
    margin-bottom: 6px;
}

.hero-cta {
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    margin-top: 22px;
}

.categories-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 22px;
}

.category-card {
    background: var(--surface);
    padding: 24px;
    border-radius: 18px;
    border: 1px solid var(--border);
    transition: transform 0.18s ease, box-shadow 0.18s ease, border-color 0.18s ease;
}

.category-card:hover {
    transform: translateY(-4px);
    box-shadow: var(--card-hover-shadow);
    border-color: rgba(120, 90, 60, 0.2);
}

.category-card p {
    color: var(--muted);
    font-size: 0.92rem;
    margin: 0 0 14px;
    line-height: 1.6;
}

.cat-link {
    color: var(--link);
    font-weight: 700;
    text-decoration: none;
    font-size: 0.92rem;
    transition: color 0.15s ease;
}

.cat-link:hover {
    color: var(--link-hover);
}

.site-footer {
    margin-top: 32px;
    text-align: center;
    color: var(--footer);
    padding: 18px 6px 40px;
    font-size: 0.9rem;
}

@media (max-width: 1100px) {
    .floating-chat { display: none; }
    .home-root { padding-right: 18px; }
}

@media (max-width: 900px) {
    .hero { grid-template-columns: 1fr; }
}

@media (max-width: 620px) {
    .site-header .header-inner { flex-direction: column; gap: 12px; }
    .top-nav a { margin-left: 0; }
    .top-nav button { margin-left: 0; width: 100%; }
    .hero { padding: 24px; }
    .page-container { padding: 18px; }
}

.floating-chat {
    position: fixed;
    top: 110px;
    right: 30px;
    bottom: 40px;
    width: calc(100% - 780px);
    max-width: 900px;
    min-width: 380px;
    background: var(--panel-bg);
    border-radius: 18px;
    padding: 24px;
    box-shadow: var(--shadow);
    border: 1px solid var(--chat-border);
    overflow: auto;
    z-index: 8;
}

.floating-chat .chat-placeholder {
    color: var(--placeholder-color);
}

.floating-chat .chat-message {
    padding: 14px 16px;
    border-radius: 14px;
    margin-bottom: 12px;
    background: var(--message-bg);
    border: 1px solid var(--message-border);
    color: var(--text);
}

.chat-message-header {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 8px;
}

.chat-avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
    border: 1px solid var(--border);
    flex-shrink: 0;
}

.chat-avatar-initial {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    background: var(--button-bg);
    color: var(--button-color);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    font-size: 0.85rem;
    font-weight: 700;
    flex-shrink: 0;
}

.chat-username {
    font-size: 0.92rem;
    color: var(--muted);
}

.chat-time {
    margin-left: auto;
    font-size: 0.78rem;
    color: var(--placeholder-color);
}

.chat-content {
    margin: 0 0 8px;
    line-height: 1.5;
}

.reactions-row {
    display: flex;
    align-items: center;
    gap: 6px;
    flex-wrap: wrap;
}

.reaction-btn {
    position: relative;
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 3px 8px;
    border-radius: 12px;
    border: 1px solid var(--border);
    background: var(--surface);
    color: var(--text);
    cursor: pointer;
    font-size: 0.82rem;
    transition: background 0.15s ease, border-color 0.15s ease;
}

.reaction-btn:hover {
    background: var(--button-ghost-bg);
}

.reaction-btn.reaction-mine {
    border-color: var(--button-bg);
    background: var(--button-ghost-bg);
}

.reaction-btn:hover::after {
    content: attr(title);
    position: absolute;
    bottom: calc(100% + 6px);
    left: 50%;
    transform: translateX(-50%);
    background: var(--surface-strong);
    border: 1px solid var(--border);
    color: var(--text);
    font-size: 0.75rem;
    font-weight: 400;
    padding: 4px 10px;
    border-radius: 8px;
    white-space: nowrap;
    z-index: 30;
    box-shadow: var(--shadow);
    pointer-events: none;
}

.reaction-emoji {
    font-size: 0.9rem;
}

.reaction-count {
    font-size: 0.78rem;
    font-weight: 600;
    color: var(--muted);
}

.emoji-picker {
    display: none;
    background: var(--surface-strong);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 4px 6px;
    gap: 2px;
    flex-wrap: wrap;
}

.chat-message:hover .emoji-picker {
    display: flex;
}

.emoji-pick {
    background: none;
    border: none;
    cursor: pointer;
    font-size: 1.1rem;
    padding: 4px;
    border-radius: 8px;
    transition: background 0.12s ease;
}

.emoji-pick:hover {
    background: var(--button-ghost-bg);
}

.chat-footer {
    margin-top: 18px;
}

.chat-form {
    display: flex;
    gap: 10px;
    align-items: center;
}

.chat-input {
    flex: 1;
    padding: 12px 14px;
    border-radius: 14px;
    border: 1px solid var(--input-border);
    background: var(--input-bg);
    color: var(--text);
    font-family: inherit;
    font-size: 0.96rem;
}

.chat-input::placeholder {
    color: var(--muted);
}

.chat-send {
    margin-left: 0;
    border: none;
    padding: 12px 20px;
    border-radius: 14px;
    background: var(--button-bg);
    color: var(--button-color);
    font-weight: 700;
    font-size: 0.96rem;
    font-family: inherit;
    cursor: pointer;
    transition: filter 0.2s ease, transform 0.18s ease;
    white-space: nowrap;
}

.chat-send:hover {
    filter: brightness(1.05);
    transform: translateY(-1px);
}

.nav-user {
    display: inline-flex;
    align-items: center;
    gap: 8px;
    text-decoration: none;
    color: var(--link);
    font-weight: 600;
    padding: 6px 12px;
    border-radius: 14px;
    transition: background 0.2s ease;
}

.nav-user:hover {
    background: var(--button-ghost-bg);
    color: var(--link-hover);
}

.nav-avatar {
    width: 34px;
    height: 34px;
    border-radius: 50%;
    object-fit: cover;
    border: 2px solid var(--border);
}

.nav-avatar-initial {
    width: 34px;
    height: 34px;
    border-radius: 50%;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background: var(--button-bg);
    color: var(--button-color);
    font-weight: 700;
    font-size: 0.85rem;
    flex-shrink: 0;
}

.nav-logout {
    color: var(--muted);
    font-weight: 600;
    text-decoration: none;
    font-size: 0.9rem;
}

.nav-logout:hover {
    color: var(--link-hover);
}

.profile-card {
    width: min(640px, 100%);
    padding: 36px;
}

.profile-header {
    text-align: center;
    margin-bottom: 28px;
}

.profile-avatar-wrap {
    position: relative;
    width: 120px;
    height: 120px;
    margin: 0 auto 18px;
    border-radius: 50%;
    overflow: hidden;
    cursor: pointer;
}

.profile-avatar {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.profile-initials {
    width: 120px;
    height: 120px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 2.8rem;
    font-weight: 700;
    background: var(--button-bg);
    color: var(--button-color);
}

.profile-avatar-overlay {
    position: absolute;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.2s ease;
    color: #fff;
    font-weight: 700;
    font-size: 0.9rem;
    border-radius: 50%;
}

.profile-avatar-wrap:hover .profile-avatar-overlay {
    opacity: 1;
}

.profile-bio {
    color: var(--muted);
    font-size: 1rem;
    line-height: 1.6;
    margin: 8px auto 0;
    max-width: 420px;
}

.profile-stats {
    display: flex;
    justify-content: center;
    gap: 40px;
    padding: 20px 0;
    margin-bottom: 24px;
    border-top: 1px solid var(--border);
    border-bottom: 1px solid var(--border);
}

.profile-stat {
    text-align: center;
}

.stat-value {
    display: block;
    font-weight: 700;
    font-size: 1.1rem;
    color: var(--text);
}

.stat-label {
    display: block;
    font-size: 0.85rem;
    color: var(--muted);
    margin-top: 2px;
}

.profile-section {
    margin-top: 28px;
    padding-top: 24px;
    border-top: 1px solid var(--border);
}

.profile-section h2 {
    margin: 0 0 16px;
    color: var(--muted);
    font-size: 1.1rem;
    letter-spacing: 0.02em;
}

.profile-textarea {
    width: 100%;
    padding: 12px 14px;
    border-radius: 14px;
    border: 1px solid var(--input-border);
    background: var(--input-bg);
    color: var(--text);
    font-family: inherit;
    font-size: 0.96rem;
    resize: vertical;
    min-height: 80px;
}

.profile-textarea:focus {
    outline: none;
    border-color: var(--button-bg);
    box-shadow: 0 0 0 4px rgba(125, 83, 52, 0.12);
}

.profile-btn {
    margin-top: 12px;
    width: 100%;
    border: none;
    padding: 14px 20px;
    font-family: inherit;
    font-size: 1rem;
    cursor: pointer;
    border-radius: 14px;
    text-align: center;
}

.profile-activity {
    display: grid;
    gap: 12px;
}

.activity-item {
    padding: 14px 16px;
    border-radius: 14px;
    background: var(--message-bg);
    border: 1px solid var(--message-border);
}

.activity-content {
    margin: 0 0 6px;
    color: var(--text);
}

.activity-meta {
    font-size: 0.85rem;
    color: var(--muted);
}

.profile-danger-zone {
    background: var(--alert-bg);
    border: 1px solid var(--alert-border);
    border-radius: 14px;
    padding: 24px;
    margin-top: 32px;
}

.profile-danger-zone p {
    color: var(--alert-color);
    margin: 0 0 16px;
    font-size: 0.95rem;
}

.danger-btn {
    background: #a04040;
    color: var(--button-color);
    border: none;
    padding: 12px 20px;
    border-radius: 14px;
    font-weight: 700;
    font-family: inherit;
    font-size: 0.96rem;
    cursor: pointer;
    transition: filter 0.2s ease, transform 0.18s ease;
}

.danger-btn:hover {
    filter: brightness(1.1);
    transform: translateY(-1px);
}

.alert-success {
    background: rgba(80, 160, 80, 0.12);
    border-color: rgba(80, 160, 80, 0.2);
    color: #3a7a3a;
}

body.theme-dark .alert-success {
    background: rgba(80, 160, 80, 0.1);
    border-color: rgba(80, 160, 80, 0.15);
    color: #6abf6a;
}

.alert-error {
    background: rgba(180, 60, 60, 0.12);
    border-color: rgba(180, 60, 60, 0.2);
    color: #a03030;
}

body.theme-dark .alert-error {
    background: rgba(180, 60, 60, 0.1);
    border-color: rgba(180, 60, 60, 0.15);
    color: #e06060;
}

class ForumChat {
  constructor() {
    this.currentCategory = null;
    this.messages = [];
    this.pollInterval = null;
    this.emojis = ["👍", "❤️", "😂", "🔥", "💪", "👊"];
    this.init();
  }

  init() {
    document.addEventListener("click", (e) => {
      const link = e.target.closest(".cat-link");
      if (!link) return;
      e.preventDefault();
      const name = link.dataset.catName;
      if (!name) return;
      this.openChat(name);
    });

    document.addEventListener("submit", (e) => {
      if (!e.target.classList.contains("chat-form")) return;
      e.preventDefault();
      this.sendMessage(e.target);
    });

    document.addEventListener("click", (e) => {
      const btn = e.target.closest(".reaction-btn");
      if (!btn) return;
      e.preventDefault();
      this.toggleReaction(btn);
    });

    document.addEventListener("click", (e) => {
      const pick = e.target.closest(".emoji-pick");
      if (!pick) return;
      e.preventDefault();
      const picker = pick.closest(".emoji-picker");
      const msgId = parseInt(picker.dataset.msgId);
      const emoji = pick.dataset.emoji;
      this.sendReaction(msgId, emoji);
    });
  }

  openChat(categoryName) {
    this.currentCategory = categoryName;
    this.messages = [];

    const pane = document.getElementById("floating-chat");

    pane.innerHTML = `
      <div class="chat-header">
        <h2>${categoryName}</h2>
      </div>
      <div id="chat-messages" class="chat-messages"
        style="height:400px;overflow-y:auto;margin:14px 0;"></div>
      <div class="chat-footer">
        <form class="chat-form">
          <input type="text" class="chat-input" placeholder="Écrire un message..." required />
          <button type="submit" class="chat-send btn primary">Envoyer</button>
        </form>
      </div>
    `;

    pane.setAttribute("aria-hidden", "false");
    this.fetchMessages();

    if (this.pollInterval) clearInterval(this.pollInterval);
    this.pollInterval = setInterval(() => this.fetchMessages(), 3000);
  }

  fetchMessages() {
    if (!this.currentCategory) return;

    fetch(`/api/messages?category=${encodeURIComponent(this.currentCategory)}`)
      .then(r => r.json())
      .then(data => {
        if (!data.success) return;
        this.renderMessages(data.data || []);
      })
      .catch(err => console.error("GET error:", err));
  }

  avatarHTML(m) {
    if (m.avatar_url) {
      return `<img src="${m.avatar_url}" class="chat-avatar" alt="">`;
    }
    const initial = m.username ? m.username[0].toUpperCase() : "?";
    return `<span class="chat-avatar-initial">${initial}</span>`;
  }

  reactionsHTML(m) {
    let html = '<div class="reactions-row">';
    const groups = m.reactions || [];

    for (const g of groups) {
      const mine = g.user_id > 0 ? " reaction-mine" : "";
      const names = (g.users || []).join(", ");
      html += `<button class="reaction-btn${mine}" data-msg-id="${m.id}" data-emoji="${g.emoji}" title="${names}">
        <span class="reaction-emoji">${g.emoji}</span>
        <span class="reaction-count">${g.count}</span>
      </button>`;
    }

    html += `<div class="emoji-picker" data-msg-id="${m.id}">`;
    for (const e of this.emojis) {
      html += `<button class="emoji-pick" data-emoji="${e}">${e}</button>`;
    }
    html += "</div></div>";

    return html;
  }

  renderMessages(messages) {
    const container = document.getElementById("chat-messages");
    if (!container) return;

    this.messages = messages;

    container.innerHTML = messages.length
      ? messages.map(m => `
          <div class="chat-message">
            <div class="chat-message-header">
              ${this.avatarHTML(m)}
              <strong class="chat-username">${m.username}</strong>
              <small class="chat-time">${new Date(m.created_at).toLocaleTimeString()}</small>
            </div>
            <p class="chat-content">${m.content}</p>
            ${this.reactionsHTML(m)}
          </div>
        `).join("")
      : "<p>Aucun message</p>";

    container.scrollTop = container.scrollHeight;
  }

  sendMessage(form) {
    if (!this.currentCategory) return;

    const input = form.querySelector("input");
    const content = input.value.trim();

    if (!content) return;

    fetch("/api/messages", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        category: this.currentCategory,
        content: content
      })
    })
      .then(r => r.json())
      .then(data => {
        if (!data.success) {
          alert(data.message || "Erreur");
          return;
        }
        input.value = "";
        this.fetchMessages();
      })
      .catch(err => console.error("POST error:", err));
  }

  toggleReaction(btn) {
    const msgId = parseInt(btn.dataset.msgId);
    const emoji = btn.dataset.emoji;
    const isMine = btn.classList.contains("reaction-mine");

    if (isMine) {
      fetch(`/api/reactions?message_id=${msgId}&emoji=${encodeURIComponent(emoji)}`, {
        method: "DELETE"
      })
        .then(r => r.json())
        .then(() => this.fetchMessages())
        .catch(err => console.error("DELETE reaction error:", err));
    } else {
      this.sendReaction(msgId, emoji);
    }
  }

  sendReaction(messageID, emoji) {
    fetch("/api/reactions", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ message_id: messageID, emoji: emoji })
    })
      .then(r => r.json())
      .then(() => this.fetchMessages())
      .catch(err => console.error("POST reaction error:", err));
  }
}

